import{_ as e,c as t,o,a}from"./app.6cebd806.js";const S=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"docs/css&html/3.浏览器是如何执行JS.md","lastUpdated":1677180519000}'),c={name:"docs/css&html/3.浏览器是如何执行JS.md"},l=a('<ul><li>编译器和解释器 <ul><li>之所以存在编译器，是因为机器并不能直接理解我们所写的代码，所以在执行程序之前，需要将我们的代码翻译成机器能理解的机器语言。</li></ul></li></ul><blockquote><p>编译型语言：在程序执行之前，需要经过编译器的编译过程，并且编译之后会直接保留机器能读懂的二进制文件，这样每次运行程序时都可以直接运行该二进制文件。</p><p>解释型语言：在每次运行时都需要通过解释器对程序进行动态解释和执行。例如Python，JavaScript属于解释型语言。</p></blockquote><h5 id="流程" tabindex="-1">流程 <a class="header-anchor" href="#流程" aria-hidden="true">#</a></h5><ol><li>编译器</li></ol><p>源代码 <code>-词法分析和语法分析-&gt;</code> AST <code>-词义分析-&gt;</code> 中间代码 <code>-代码优化-&gt;</code> 二进制文件 <code>-直接执行-&gt;</code> 执行</p><ol start="2"><li>解释器</li></ol><p>源代码 <code>-词法分析和语法分析-&gt;</code> AST <code>-词义分析-&gt;</code> 字节码 <code>-解释执行-&gt;</code> 执行</p><h4 id="v8执行代码流程" tabindex="-1">V8执行代码流程 <a class="header-anchor" href="#v8执行代码流程" aria-hidden="true">#</a></h4><p><img src="https://cdn.nlark.com/yuque/0/2020/png/305942/1594974392146-775bfa1d-9ae6-4bb0-8c0d-e148c249943a.png" alt=""></p><ol><li>通过词法分析，语法分析生成抽象语法树 AST和执行上下文 <ul><li>第一阶段是分词（词法分析），作用是将一行行源码拆解成一个个 token。所谓token是指语法上不可再分的最小的单个字符或字符串</li><li>第二阶段是解析（语法分析），作用是将上一步生成的token数据，根据语法规则转为AST，如果源码符合语法规则，这一步就会顺利完成，否则会抛出错误。</li></ul></li><li>根据AST生成字节码</li><li>执行代码</li></ol>',10),d=[l];function i(_,s,r,n,p,h){return o(),t("div",null,d)}const m=e(c,[["render",i]]);export{S as __pageData,m as default};
